import{_ as e,o,c as a,a2 as c}from"./chunks/framework.CGYl2SZ_.js";const t=JSON.parse('{"title":"presence","description":"presence 页面","frontmatter":{"title":"presence","description":"presence 页面"},"headers":[],"relativePath":"concepts/presence.md","filePath":"concepts/presence.md"}');const d=e({name:"concepts/presence.md"},[["render",function(e,t,d,i,n,l){return o(),a("div",null,[...t[0]||(t[0]=[c('<h1 id="在线状态" tabindex="-1">在线状态 <a class="header-anchor" href="#在线状态" aria-label="Permalink to &quot;在线状态&quot;">​</a></h1><h1 id="在线状态-1" tabindex="-1">在线状态 <a class="header-anchor" href="#在线状态-1" aria-label="Permalink to &quot;在线状态&quot;">​</a></h1><p>OpenClaw &quot;在线状态&quot;是一个轻量级、尽力而为的视图，显示：</p><ul><li><strong>网关</strong>本身，以及</li><li><strong>连接到网关的客户端</strong>（mac 应用、WebChat、CLI 等）</li></ul><p>在线状态主要用于渲染 macOS 应用的<strong>实例</strong>选项卡并提供快速操作员可见性。</p><h2 id="在线状态字段-显示什么" tabindex="-1">在线状态字段（显示什么） <a class="header-anchor" href="#在线状态字段-显示什么" aria-label="Permalink to &quot;在线状态字段（显示什么）&quot;">​</a></h2><p>在线状态条目是结构化对象，具有如下字段：</p><ul><li><code>instanceId</code>（可选但强烈推荐）：稳定的客户端身份（通常为 <code>connect.client.instanceId</code>）</li><li><code>host</code>：友好主机名</li><li><code>ip</code>：尽力而为的 IP 地址</li><li><code>version</code>：客户端版本字符串</li><li><code>deviceFamily</code> / <code>modelIdentifier</code>：硬件提示</li><li><code>mode</code>：<code>ui</code>、<code>webchat</code>、<code>cli</code>、<code>backend</code>、<code>probe</code>、<code>test</code>、<code>node</code>、...</li><li><code>lastInputSeconds</code>：&quot;距离上次用户输入的秒数&quot;（如果已知）</li><li><code>reason</code>：<code>self</code>、<code>connect</code>、<code>node-connected</code>、<code>periodic</code>、...</li><li><code>ts</code>：上次更新时间戳（自纪元以来的毫秒数）</li></ul><h2 id="生产者-在线状态来自哪里" tabindex="-1">生产者（在线状态来自哪里） <a class="header-anchor" href="#生产者-在线状态来自哪里" aria-label="Permalink to &quot;生产者（在线状态来自哪里）&quot;">​</a></h2><p>在线状态条目由多个来源产生并<strong>合并</strong>。</p><h3 id="_1-网关自条目" tabindex="-1">1) 网关自条目 <a class="header-anchor" href="#_1-网关自条目" aria-label="Permalink to &quot;1) 网关自条目&quot;">​</a></h3><p>网关总是在启动时种入一个&quot;self&quot;条目，以便 UI 在任何客户端连接之前显示网关主机。</p><h3 id="_2-websocket-连接" tabindex="-1">2) WebSocket 连接 <a class="header-anchor" href="#_2-websocket-连接" aria-label="Permalink to &quot;2) WebSocket 连接&quot;">​</a></h3><p>每个 WS 客户端以 <code>connect</code> 请求开始。成功握手后，网关为该连接 upsert 在线状态条目。</p><h4 id="为什么一次性-cli-命令不显示" tabindex="-1">为什么一次性 CLI 命令不显示 <a class="header-anchor" href="#为什么一次性-cli-命令不显示" aria-label="Permalink to &quot;为什么一次性 CLI 命令不显示&quot;">​</a></h4><p>CLI 通常连接执行短期、一次性命令。为避免污染实例列表，<code>client.mode === &quot;cli&quot;</code> <strong>不会</strong>转换为在线状态条目。</p><h3 id="_3-system-event-信标" tabindex="-1">3) <code>system-event</code> 信标 <a class="header-anchor" href="#_3-system-event-信标" aria-label="Permalink to &quot;3) `system-event` 信标&quot;">​</a></h3><p>客户端可以通过 <code>system-event</code> 方法发送更丰富的周期性信标。mac 应用使用它来报告主机名、IP 和 <code>lastInputSeconds</code>。</p><h3 id="_4-节点连接-角色-node" tabindex="-1">4) 节点连接（角色：node） <a class="header-anchor" href="#_4-节点连接-角色-node" aria-label="Permalink to &quot;4) 节点连接（角色：node）&quot;">​</a></h3><p>当节点通过网关 WebSocket 连接并带有 <code>role: node</code> 时，网关为该节点 upsert 在线状态条目（与其他 WS 客户端相同流程）。</p><h2 id="合并-去重规则-为什么-instanceid-很重要" tabindex="-1">合并 + 去重规则（为什么 <code>instanceId</code> 很重要） <a class="header-anchor" href="#合并-去重规则-为什么-instanceid-很重要" aria-label="Permalink to &quot;合并 + 去重规则（为什么 `instanceId` 很重要）&quot;">​</a></h2><p>在线状态条目存储在单个内存映射中：</p><ul><li>条目按键<strong>在线状态键</strong>。</li><li>最好的键是一个稳定的 <code>instanceId</code>（来自 <code>connect.client.instanceId</code>），它能在重启后存活。</li><li>键不区分大小写。</li></ul><p>如果客户端重新连接而没有稳定的 <code>instanceId</code>，它可能会显示为<strong>重复</strong>行。</p><h2 id="ttl-和有界大小" tabindex="-1">TTL 和有界大小 <a class="header-anchor" href="#ttl-和有界大小" aria-label="Permalink to &quot;TTL 和有界大小&quot;">​</a></h2><p>在线状态故意是临时的：</p><ul><li><strong>TTL：</strong> 超过 5 分钟的条目被清除</li><li><strong>最大条目数：</strong> 200（最旧的先丢弃）</li></ul><p>这保持列表新鲜并避免无限制的内存增长。</p><h2 id="远程-隧道注意事项-回环-ip" tabindex="-1">远程/隧道注意事项（回环 IP） <a class="header-anchor" href="#远程-隧道注意事项-回环-ip" aria-label="Permalink to &quot;远程/隧道注意事项（回环 IP）&quot;">​</a></h2><p>当客户端通过 SSH 隧道 / 本地端口转发连接时，网关可能将远程地址视为 <code>127.0.0.1</code>。为避免覆盖良好的客户端报告 IP，忽略回环远程地址。</p><h2 id="消费者" tabindex="-1">消费者 <a class="header-anchor" href="#消费者" aria-label="Permalink to &quot;消费者&quot;">​</a></h2><h3 id="macos-实例选项卡" tabindex="-1">macOS 实例选项卡 <a class="header-anchor" href="#macos-实例选项卡" aria-label="Permalink to &quot;macOS 实例选项卡&quot;">​</a></h3><p>macOS 应用呈现 <code>system-presence</code> 的输出，并根据上次更新的年龄应用小的状态指示器（Active/Idle/Stale）。</p><h2 id="调试提示" tabindex="-1">调试提示 <a class="header-anchor" href="#调试提示" aria-label="Permalink to &quot;调试提示&quot;">​</a></h2><ul><li>要查看原始列表，请对网关调用 <code>system-presence</code>。</li><li>如果看到重复项： <ul><li>确认客户端在握手中发送稳定的 <code>client.instanceId</code></li><li>确认定期信标使用相同的 <code>instanceId</code></li><li>检查连接派生条目是否缺少 <code>instanceId</code>（重复是预期的）</li></ul></li></ul>',35)])])}]]);export{t as __pageData,d as default};
